import { Link } from 'react-router'
import { Plus, Search, MoreHorizontal, Trash2, Pencil, Archive } from 'lucide-react'
import { useProjects } from '@/hooks/use-projects'
import { cn } from '@/lib/utils'
import type { Project } from '@/types'

function formatRelativeDate(dateStr: string): string {
  const date = new Date(dateStr)
  const now = new Date()
  const diffMs = now.getTime() - date.getTime()
  const diffMins = Math.floor(diffMs / 60000)
  const diffHours = Math.floor(diffMs / 3600000)
  const diffDays = Math.floor(diffMs / 86400000)

  if (diffMins < 1) return 'just now'
  if (diffMins < 60) return `${diffMins}m ago`
  if (diffHours < 24) return `${diffHours}h ago`
  if (diffDays < 7) return `${diffDays}d ago`
  if (diffDays < 30) return `${Math.floor(diffDays / 7)}w ago`
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

type SortKey = 'name' | 'updatedAt'

export default function DashboardPage() {
  const { projects, isLoading, deleteProject, isDeleting } = useProjects()
  const [search, setSearch] = useState('')
  const [sortBy, setSortBy] = useState<SortKey>('updatedAt')
  const [deleteTarget, setDeleteTarget] = useState<Project | null>(null)
  const [openMenu, setOpenMenu] = useState<string | null>(null)

  const filtered = projects
    .filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
      if (sortBy === 'name') return a.name.localeCompare(b.name)
      return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
    })

  const handleDelete = async () => {
    if (!deleteTarget) return
    try {
      await deleteProject(deleteTarget.id)
    } finally {
      setDeleteTarget(null)
    }
  }

  return (
    <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-text">Projects</h1>
          <p className="mt-1 text-sm text-text-muted">Manage your Minecraft plugin projects</p>
        </div>
        <Link
          to="/projects/new"
          className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary-hover"
        >
          <Plus className="h-4 w-4" />
          New Project
        </Link>
      </div>

      {!isLoading && projects.length > 0 && (
        <div className="mt-6 flex items-center gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-text-dim" />
            <input
              type="text"
              placeholder="Search projects..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full rounded-lg border border-border bg-surface py-2 pl-9 pr-3 text-sm text-text placeholder:text-text-dim focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
            />
          </div>
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value as SortKey)}
            className="rounded-lg border border-border bg-surface px-3 py-2 text-sm text-text-muted focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
          >
            <option value="updatedAt">Last updated</option>
            <option value="name">Name</option>
          </select>
        </div>
      )}

      {isLoading ? (
        <div className="mt-6 grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="animate-pulse rounded-xl border border-border bg-surface p-5">
              <div className="h-5 w-32 rounded bg-border" />
              <div className="mt-3 h-3 w-48 rounded bg-border" />
              <div className="mt-4 flex gap-2">
                <div className="h-5 w-14 rounded bg-border" />
                <div className="h-5 w-14 rounded bg-border" />
              </div>
            </div>
          ))}
        </div>
      ) : (
        <>
          <div className="mt-6 grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
            {filtered.map((project) => (
              <div key={project.id} className="group relative rounded-xl border border-border bg-surface transition-colors hover:border-border-bright hover:bg-surface-hover">
                <Link
                  to={`/workspace/${project.id}`}
                  className="block p-5"
                >
                  <div className="flex items-start justify-between">
                    <div className="flex-1 pr-8">
                      <h3 className="font-medium text-text group-hover:text-primary">
                        {project.name}
                      </h3>
                      {project.description && (
                        <p className="mt-1 line-clamp-2 text-xs text-text-dim">{project.description}</p>
                      )}
                      <div className="mt-2 flex items-center gap-2">
                        <span className="rounded bg-accent px-2 py-0.5 text-xs text-text-muted">
                          {project.software}
                        </span>
                        <span className="rounded bg-accent px-2 py-0.5 text-xs text-text-muted">
                          {project.language}
                        </span>
                        {project.status === 'archived' && (
                          <span className="flex items-center gap-1 rounded bg-warning/10 px-2 py-0.5 text-xs text-warning">
                            <Archive className="h-3 w-3" />
                            Archived
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                  <p className="mt-3 text-xs text-text-dim">Updated {formatRelativeDate(project.updatedAt)}</p>
                </Link>

                {/* Context menu trigger */}
                <div className="absolute right-4 top-5">
                  <button
                    onClick={(e) => {
                      e.preventDefault()
                      e.stopPropagation()
                      setOpenMenu(openMenu === project.id ? null : project.id)
                    }}
                    className="rounded p-1 text-text-dim hover:bg-accent hover:text-text-muted"
                  >
                    <MoreHorizontal className="h-4 w-4" />
                  </button>

                  {openMenu === project.id && (
                    <>
                      <div className="fixed inset-0 z-10" onClick={() => setOpenMenu(null)} />
                      <div className="absolute right-0 top-8 z-20 w-40 rounded-lg border border-border bg-surface py-1 shadow-lg">
                        <Link
                          to={`/workspace/${project.id}`}
                          className="flex w-full items-center gap-2 px-3 py-2 text-left text-xs text-text-muted hover:bg-surface-hover hover:text-text"
                          onClick={() => setOpenMenu(null)}
                        >
                          <Pencil className="h-3 w-3" />
                          Open Project
                        </Link>
                        <button
                          onClick={(e) => {
                            e.preventDefault()
                            e.stopPropagation()
                            setOpenMenu(null)
                            setDeleteTarget(project)
                          }}
                          className="flex w-full items-center gap-2 px-3 py-2 text-left text-xs text-destructive hover:bg-destructive/10"
                        >
                          <Trash2 className="h-3 w-3" />
                          Delete Project
                        </button>
                      </div>
                    </>
                  )}
                </div>
              </div>
            ))}
          </div>

          {filtered.length === 0 && search && (
            <div className="mt-12 text-center">
              <p className="text-text-muted">No projects match "{search}"</p>
              <button
                onClick={() => setSearch('')}
                className="mt-2 text-sm font-medium text-primary hover:text-primary-hover"
              >
                Clear search
              </button>
            </div>
          )}

          {projects.length === 0 && (
            <div className="mt-16 flex flex-col items-center text-center">
              <div className="rounded-2xl bg-primary/10 p-4">
                <Plus className="h-8 w-8 text-primary" />
              </div>
              <h2 className="mt-4 text-lg font-semibold text-text">No projects yet</h2>
              <p className="mt-1 max-w-sm text-sm text-text-muted">
                Create your first Minecraft plugin project and let AI help you build it.
              </p>
              <Link
                to="/projects/new"
                className="mt-6 inline-flex items-center gap-2 rounded-lg bg-primary px-5 py-2.5 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary-hover"
              >
                <Plus className="h-4 w-4" />
                Create your first project
              </Link>
            </div>
          )}
        </>
      )}

      {/* Delete confirmation dialog */}
      {deleteTarget && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
          <div className="mx-4 w-full max-w-sm rounded-xl border border-border bg-surface p-6 shadow-xl">
            <h3 className="text-lg font-semibold text-text">Delete project?</h3>
            <p className="mt-2 text-sm text-text-muted">
              Are you sure you want to delete <span className="font-medium text-text">{deleteTarget.name}</span>? This action cannot be undone.
            </p>
            <div className="mt-6 flex items-center justify-end gap-3">
              <button
                onClick={() => setDeleteTarget(null)}
                disabled={isDeleting}
                className="rounded-lg border border-border px-4 py-2 text-sm text-text-muted transition-colors hover:bg-surface-hover disabled:opacity-50"
              >
                Cancel
              </button>
              <button
                onClick={handleDelete}
                disabled={isDeleting}
                className={cn(
                  'rounded-lg px-4 py-2 text-sm font-medium text-destructive-foreground transition-colors',
                  isDeleting ? 'bg-destructive/70' : 'bg-destructive hover:bg-destructive/90'
                )}
              >
                {isDeleting ? 'Deleting...' : 'Delete'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
","referencedBy":{}},{"path":"client/src/pages/workspace.tsx","content":"import { useState, useRef, useEffect, useCallback } from 'react'
import { Link, useParams } from 'react-router'
import Editor from '@monaco-editor/react'
import {
  ArrowLeft,
  ChevronRight,
  ChevronDown,
  File,
  Folder,
  Play,
  Settings,
  Send,
  MessageSquare,
  Bot,
  User,
  Loader2,
  AlertCircle,
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { useProject } from '@/hooks/use-projects'
import { useAgentSessions, useAgentSession } from '@/hooks/use-agent'

interface FileNode {
  name: string
  type: 'file' | 'folder'
  children?: FileNode[]
}

const mockFileTree: FileNode[] = [
  {
    name: 'src',
    type: 'folder',
    children: [
      {
        name: 'main',
        type: 'folder',
        children: [
          {
            name: 'java',
            type: 'folder',
            children: [
              {
                name: 'com.example.plugin',
                type: 'folder',
                children: [
                  { name: 'Main.java', type: 'file' },
                  { name: 'CommandHandler.java', type: 'file' },
                  { name: 'EventListener.java', type: 'file' },
                ],
              },
            ],
          },
          {
            name: 'resources',
            type: 'folder',
            children: [
              { name: 'plugin.yml', type: 'file' },
              { name: 'config.yml', type: 'file' },
            ],
          },
        ],
      },
    ],
  },
  { name: 'build.gradle', type: 'file' },
  { name: 'README.md', type: 'file' },
]

const placeholderCode = `package com.example.plugin;

import org.bukkit.plugin.java.JavaPlugin;

public class Main extends JavaPlugin {

    @Override
    public void onEnable() {
        getLogger().info("Plugin enabled!");
        // Register commands and events here
    }

    @Override
    public void onDisable() {
        getLogger().info("Plugin disabled!");
    }
}
`

function FileTreeNode({ node, depth = 0, selectedFile, onSelect }: {
  node: FileNode
  depth?: number
  selectedFile: string
  onSelect: (name: string) => void
}) {
  const [open, setOpen] = useState(depth < 3)

  return (
    <div>
      <button
        onClick={() => {
          if (node.type === 'folder') {
            setOpen(!open)
          } else {
            onSelect(node.name)
          }
        }}
        className={cn(
          'flex w-full items-center gap-1.5 rounded px-2 py-1 text-left text-xs transition-colors hover:bg-surface-hover',
          node.type === 'file' && node.name === selectedFile
            ? 'bg-primary/10 text-primary'
            : node.type === 'file'
              ? 'text-text-muted'
              : 'text-text'
        )}
        style={{ paddingLeft: `${depth * 12 + 8}px` }}
      >
        {node.type === 'folder' ? (
          open ? <ChevronDown className="h-3 w-3 shrink-0 text-text-dim" /> : <ChevronRight className="h-3 w-3 shrink-0 text-text-dim" />
        ) : (
          <span className="w-3" />
        )}
        {node.type === 'folder' ? (
          <Folder className="h-3.5 w-3.5 shrink-0 text-primary/70" />
        ) : (
          <File className="h-3.5 w-3.5 shrink-0 text-text-dim" />
        )}
        <span className="truncate">{node.name}</span>
      </button>
      {node.type === 'folder' && open && node.children?.map((child) => (
        <FileTreeNode
          key={child.name}
          node={child}
          depth={depth + 1}
          selectedFile={selectedFile}
          onSelect={onSelect}
        />
      ))}
    </div>
  )
}

function ChatPanel({ projectId }: { projectId: string }) {
  const { sessions, isLoading: sessionsLoading, createSession } = useAgentSessions(projectId)

  const initialSessionId = sessions.length > 0 ? sessions[0].id : null
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null)
  const resolvedSessionId = activeSessionId ?? initialSessionId

  if (sessionsLoading) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <Loader2 className="h-5 w-5 animate-spin text-text-dim" />
      </div>
    )
  }

  if (!resolvedSessionId) {
    return <ChatEmptyState onSessionCreated={setActiveSessionId} createSession={createSession} />
  }

  return <ChatSession projectId={projectId} sessionId={resolvedSessionId} />
}

function ChatEmptyState({ onSessionCreated, createSession }: {
  onSessionCreated: (id: string) => void
  createSession: () => Promise<{ id: string }>
}) {
  const [input, setInput] = useState('')
  const [isCreating, setIsCreating] = useState(false)

  const handleSend = async () => {
    const trimmed = input.trim()
    if (!trimmed || isCreating) return
    setIsCreating(true)
    try {
      const session = await createSession()
      onSessionCreated(session.id)
    } catch {
      setIsCreating(false)
    }
  }

  return (
    <>
      <div className="flex-1 overflow-y-auto p-4">
        <div className="flex flex-col items-center justify-center py-12 text-center">
          <div className="mb-3 rounded-xl bg-primary/10 p-3">
            <MessageSquare className="h-6 w-6 text-primary" />
          </div>
          <p className="text-sm font-medium text-text">Start a conversation</p>
          <p className="mt-1 text-xs text-text-dim">
            Describe what you want to build and the AI agent will help you create it.
          </p>
        </div>
      </div>
      <div className="border-t border-border p-3">
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend() } }}
            placeholder="Describe your plugin idea..."
            disabled={isCreating}
            className="flex-1 rounded-lg border border-border bg-background px-3 py-2 text-sm text-text placeholder:text-text-dim focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-50"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isCreating}
            className="rounded-lg bg-primary p-2 text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            {isCreating ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
          </button>
        </div>
      </div>
    </>
  )
}

function ChatSession({ projectId, sessionId }: { projectId: string; sessionId: string }) {
  const { session, messages, isLoading, sendMessage, isSending } = useAgentSession(projectId, sessionId)
  const [input, setInput] = useState('')
  const messagesEndRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  const handleSend = useCallback(async () => {
    const trimmed = input.trim()
    if (!trimmed || isSending) return
    setInput('')
    await sendMessage(trimmed)
  }, [input, isSending, sendMessage])

  if (isLoading) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <Loader2 className="h-5 w-5 animate-spin text-text-dim" />
      </div>
    )
  }

  const statusColor =
    session?.status === 'running' ? 'text-warning' :
    session?.status === 'completed' ? 'text-success' :
    session?.status === 'failed' ? 'text-destructive' :
    'text-text-dim'

  return (
    <>
      <div className="flex-1 overflow-y-auto p-4">
        {messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-center">
            <div className="mb-3 rounded-xl bg-primary/10 p-3">
              <MessageSquare className="h-6 w-6 text-primary" />
            </div>
            <p className="text-sm font-medium text-text">Session started</p>
            <p className="mt-1 text-xs text-text-dim">Send a message to begin.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {messages.map((msg) => (
              <div key={msg.id} className="flex gap-2.5">
                <div className={cn(
                  'mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full',
                  msg.role === 'user' ? 'bg-primary/10' : 'bg-surface-hover'
                )}>
                  {msg.role === 'user'
                    ? <User className="h-3.5 w-3.5 text-primary" />
                    : <Bot className="h-3.5 w-3.5 text-text-muted" />}
                </div>
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-medium text-text-muted">
                    {msg.role === 'user' ? 'You' : msg.role === 'system' ? 'System' : 'AI Agent'}
                  </p>
                  <p className="mt-0.5 whitespace-pre-wrap text-sm text-text">{msg.content}</p>
                </div>
              </div>
            ))}
            {isSending && (
              <div className="flex gap-2.5">
                <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-surface-hover">
                  <Loader2 className="h-3.5 w-3.5 animate-spin text-text-muted" />
                </div>
                <div>
                  <p className="text-xs font-medium text-text-muted">AI Agent</p>
                  <p className="mt-0.5 text-sm text-text-dim">Processing...</p>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>
      <div className="border-t border-border p-3">
        {session && session.status !== 'idle' && session.status !== 'running' && (
          <div className="mb-2 flex items-center gap-1.5 text-xs">
            <AlertCircle className={cn('h-3 w-3', statusColor)} />
            <span className={statusColor}>Session {session.status}</span>
          </div>
        )}
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend() } }}
            placeholder="Describe your plugin idea..."
            disabled={isSending}
            className="flex-1 rounded-lg border border-border bg-background px-3 py-2 text-sm text-text placeholder:text-text-dim focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-50"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isSending}
            className="rounded-lg bg-primary p-2 text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            {isSending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
          </button>
        </div>
      </div>
    </>
  )
}

export default function WorkspacePage() {
  const { projectId } = useParams<{ projectId: string }>()
  const { project, isLoading } = useProject(projectId ?? '')
  const [selectedFile, setSelectedFile] = useState('Main.java')

  if (isLoading) {
    return (
      <div className="flex h-screen items-center justify-center bg-background">
        <div className="flex flex-col items-center gap-3">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
          <p className="text-sm text-text-muted">Loading workspace...</p>
        </div>
      </div>
    )
  }

  if (!project) {
    return (
      <div className="flex h-screen flex-col items-center justify-center bg-background">
        <AlertCircle className="h-8 w-8 text-destructive" />
        <p className="mt-3 text-sm text-text-muted">Project not found</p>
        <Link to="/dashboard" className="mt-4 text-sm font-medium text-primary hover:text-primary-hover">
          Back to dashboard
        </Link>
      </div>
    )
  }

  return (
    <div className="flex h-screen flex-col bg-background">
      {/* Top bar */}
      <header className="flex h-12 items-center justify-between border-b border-border bg-surface px-4">
        <div className="flex items-center gap-3">
          <Link to="/dashboard" className="text-text-dim hover:text-text-muted">
            <ArrowLeft className="h-4 w-4" />
          </Link>
          <span className="text-sm font-medium text-text">{project.name}</span>
          <span className="rounded bg-accent px-2 py-0.5 text-xs text-text-dim">{project.software}</span>
          <span className="rounded bg-accent px-2 py-0.5 text-xs text-text-dim">{project.language}</span>
        </div>
        <div className="flex items-center gap-2">
          <button
            className="inline-flex items-center gap-1.5 rounded-md bg-success/10 px-3 py-1.5 text-xs font-medium text-success opacity-50"
            disabled
          >
            <Play className="h-3 w-3" />
            Compile
          </button>
          <button className="rounded-md border border-border p-1.5 text-text-dim hover:text-text-muted">
            <Settings className="h-4 w-4" />
          </button>
        </div>
      </header>

      {/* Main workspace */}
      <div className="flex flex-1 overflow-hidden">
        {/* File tree */}
        <aside className="w-56 shrink-0 overflow-y-auto border-r border-border bg-surface py-2">
          <p className="mb-2 px-3 text-xs font-medium uppercase tracking-wider text-text-dim">
            Files
          </p>
          {mockFileTree.map((node) => (
            <FileTreeNode
              key={node.name}
              node={node}
              selectedFile={selectedFile}
              onSelect={setSelectedFile}
            />
          ))}
        </aside>

        {/* Editor */}
        <main className="flex-1 overflow-hidden">
          <div className="flex h-full flex-col">
            <div className="flex h-9 items-center border-b border-border bg-surface px-4">
              <div className="flex items-center gap-2 rounded bg-surface-hover px-2 py-1 text-xs text-text-muted">
                <File className="h-3 w-3" />
                {selectedFile}
              </div>
            </div>
            <div className="flex-1">
              <Editor
                height="100%"
                language="java"
                theme="vs-dark"
                value={placeholderCode}
                options={{
                  readOnly: true,
                  fontSize: 13,
                  minimap: { enabled: false },
                  scrollBeyondLastLine: false,
                  padding: { top: 12 },
                  lineNumbers: 'on',
                  renderLineHighlight: 'line',
                  cursorBlinking: 'smooth',
                  smoothScrolling: true,
                  fontFamily: "'JetBrains Mono', 'Fira Code', 'Cascadia Code', Menlo, monospace",
                  fontLigatures: true,
                }}
              />
            </div>
          </div>
        </main>

        {/* Chat panel */}
        <aside className="flex w-80 shrink-0 flex-col border-l border-border bg-surface">
          <div className="flex items-center gap-2 border-b border-border px-4 py-3">
            <MessageSquare className="h-4 w-4 text-primary" />
            <span className="text-sm font-medium text-text">AI Assistant</span>
          </div>
          <ChatPanel projectId={project.id} />
        </aside>
      </div>
    </div>
  )
}
